sql:
SELECT station_id, AVG(registered) AS average_registered_users
FROM bike_rentals
GROUP BY station_id;

SELECT user_id, SUM(distance_km) AS total_distance_km
FROM user_rentals
GROUP BY user_id;

SELECT AVG(rentals_per_type) AS average_rentals_per_type
FROM (
  SELECT user_type, COUNT(rental_id) AS rentals_per_type
  FROM bike_rentals
  GROUP BY user_type
) AS subquery;

SELECT count
FROM bike_rentals
WHERE rental_id = 1;

external_knowledge:
- 'seasoned travelers' refers to registered users;
- 'breeze' is metaphorical for weather conditions;
- 'journey longer than a brief stroll' means an average distance traveled greater than 10 kilometers;
- 'past year' refers to the year 2022.

sql:
SELECT SUM(count) AS total_rentals
FROM bike_rentals
WHERE strftime('%m', datetime) = '08';

SELECT DISTINCT users.user_name
FROM users
JOIN user_rentals ON users.user_id = user_rentals.user_id;

SELECT rental_id
FROM rental_logs
WHERE distance_km > 2.5;
